using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Shared tool state ---
var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// --- Define tools with explicit schemas ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to find information about")] string query) =>
            SearchWebAsync(query, httpClient),
        "search_web",
        "Search the web for information on a topic. Returns text snippets from top results."),

    AIFunctionFactory.Create(
        ([Description("The note content to save")] string content,
         [Description("Category for organizing notes, e.g. 'background', 'statistics', 'key-finding'")] string? category) =>
            notebook.TakeNote(content, category),
        "take_note",
        "Save a research note with an optional category tag for organization."),

    AIFunctionFactory.Create(
        notebook.GetNotes,
        "get_notes",
        "Retrieve all saved research notes, grouped by category."),
};

// --- Create the agent with Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics by searching the web and taking organized notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0.2f,
            MaxOutputTokens = 4096,
            Tools = [.. tools],
        },
    });

agent.Instructions = """
    You are a research agent. Your job is to thoroughly research a topic by searching
    the web, taking organized notes on key findings, and producing a comprehensive summary.

    Follow this workflow:
    1. Break the research topic into 3-5 specific sub-questions.
    2. Search the web for each sub-question using the search_web tool.
    3. Take notes on important findings using take_note with descriptive categories.
    4. After gathering enough information, retrieve your notes with get_notes.
    5. Produce a well-organized summary with sections, key points, and source attribution.

    Be thorough but concise. Always cite sources when possible. If a search fails,
    try rephrasing the query. Aim for at least 3 searches before summarizing.
    """;

// --- Get the research topic from the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();
await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"\n📝 Research complete. {notebook.NoteCount} note(s) taken.");

// ---------------------------------------------------------------------------
// Tool implementation: web search via DuckDuckGo Lite (no API key required)
// ---------------------------------------------------------------------------
static async Task<string> SearchWebAsync(string query, HttpClient httpClient)
{
    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
        var html = await httpClient.GetStringAsync(url);

        // Strip HTML tags and collapse whitespace
        var text = Regex.Replace(html, "<[^>]+>", " ");
        text = Regex.Replace(text, @"\s+", " ").Trim();

        return text.Length > 4000
            ? text[..4000] + "\n[Results truncated]"
            : text;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try rephrasing the query.";
    }
}

// ---------------------------------------------------------------------------
// Notebook: in-memory note-taking tool for the agent
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<(string Content, string Category, DateTime Timestamp)> _notes = [];

    public int NoteCount => _notes.Count;

    public string TakeNote(string content, string? category = null)
    {
        var cat = category ?? "general";
        _notes.Add((content, cat, DateTime.UtcNow));
        return $"Note saved under '{cat}'. Total notes: {_notes.Count}";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        var sb = new StringBuilder();
        foreach (var group in _notes.GroupBy(n => n.Category))
        {
            sb.AppendLine($"## {group.Key}");
            foreach (var (content, _, timestamp) in group)
            {
                sb.AppendLine($"- [{timestamp:HH:mm:ss UTC}] {content}");
            }

            sb.AppendLine();
        }

        return sb.ToString();
    }
}

